class Solution {
    public int lengthAfterTransformations(String s, int t, List<Integer> nums) {
        int[] cycleLengths = new int[26];
        for (int i = 0; i < 26; i++) {
            int num = nums.get(i);
            cycleLengths[i] = (num + 1) % 26 == 0 ? 26 : (num + 1) % 26;
        }

        long[] dp = new long[26];
        for (char c : s.toCharArray()) {
            dp[c - 'a']++;
        }

        long result = 0;
        final int MOD = (int) 1e9 + 7;
        for (int i = 0; i < 26; i++) {
            long cycleLength = cycleLengths[i];
            long count = dp[i];
            long cycleCount = count % (cycleLength * 26);
            long extraCycles = (t - cycleCount) / (cycleLength * 26);
            long finalCount = (count + extraCycles * cycleLength * 26) * t % MOD;
            result = (result + finalCount) % MOD;
        }
        return (int) result;
    }
}
